INSERT INTO messages (id_messages, content, sent_at, `read`, fk_users_id_sent, fk_users_id_received, fk_conversations_id) VALUES
(1,  '¡Hola! ¿Siguen disponibles los auriculares?',                    '2024-10-10 10:05:00', 1, 16, 4,  1),
(2,  'Sí, están disponibles. ¿Cuándo puedes recogerlos?',              '2024-10-10 10:30:00', 1, 4,  16, 1),
(3,  'Perfecto, me lo quedo. ¿Aceptas Bizum?',                         '2024-10-10 11:00:00', 1, 16, 4,  1),
(4,  'Sí, te paso el número.',                                          '2024-10-10 11:15:00', 1, 4,  16, 1),
(5,  'Buenos días, ¿el proyector holográfico funciona bien?',           '2024-10-20 11:10:00', 1, 14, 5,  2),
(6,  'Sí, funciona perfecto. Poco uso.',                                '2024-10-20 11:40:00', 1, 5,  14, 2),
(7,  'Me lo quedo, ¿envío o recogida?',                                '2024-10-20 12:00:00', 1, 14, 5,  2),
(8,  'Envío por Correos, con seguimiento.',                             '2024-10-20 12:20:00', 1, 5,  14, 2),
(9,  '¿La cámara tiene tarjeta de memoria incluida?',                  '2024-10-15 12:15:00', 1, 9,  6,  3),
(10, 'No incluye tarjeta, pero admite microSD estándar.',               '2024-10-15 12:50:00', 1, 6,  9,  3),
(11, 'Perfecto, ¿hacemos el envío?',                                    '2024-10-15 13:10:00', 1, 9,  6,  3),
(12, 'Sí, dime tu dirección.',                                          '2024-10-15 13:30:00', 1, 6,  9,  3),
(13, '¿Qué alcance tienen los walkie talkies?',                        '2024-10-25 13:20:00', 1, 10, 7,  4),
(14, 'Unos 300 metros en campo abierto. Funciona bien.',               '2024-10-25 14:00:00', 1, 7,  10, 4),
(15, 'Perfecto para mis hijos. Lo compro.',                             '2024-10-25 14:15:00', 1, 10, 7,  4),
(16, 'Hola, ¿cuántos juegos tiene integrados la consola?',             '2024-11-05 14:30:00', 1, 11, 8,  5),
(17, 'Tiene 200 juegos preinstalados. Pantalla sin rayajos.',           '2024-11-05 15:00:00', 1, 8,  11, 5),
(18, 'Me la quedo, ¿haces envío a Sevilla?',                           '2024-11-05 15:20:00', 1, 11, 8,  5),
(19, 'Sí, envío a toda España.',                                        '2024-11-05 15:40:00', 1, 8,  11, 5),
(20, '¿El LEGO Camión tiene todas las piezas?',                        '2024-11-15 16:10:00', 1, 8,  10, 7),
(21, 'Sí, lo monté y desmonté una vez. Completo.',                     '2024-11-15 16:40:00', 1, 10, 8,  7),
(22, 'Me lo llevo. ¿Tienes bolsa o caja?',                             '2024-11-15 17:00:00', 1, 8,  10, 7),
(23, 'Tiene la caja original un poco desgastada.',                      '2024-11-15 17:20:00', 1, 10, 8,  7),
(24, '¿La figura de Peely está completa?',                             '2024-11-18 17:15:00', 1, 16, 13, 8),
(25, 'Sí, completa y en perfecto estado. Solo la expuse.',             '2024-11-18 17:45:00', 1, 13, 16, 8),
(26, 'Genial, la compro. ¿Aceptas PayPal?',                            '2024-11-18 18:00:00', 1, 16, 13, 8),
(27, 'Sí, te mando el link.',                                           '2024-11-18 18:15:00', 1, 13, 16, 8),
(28, '¿El drone tiene alguna hélice rota?',                            '2025-03-25 17:20:00', 1, 10, 9,  28),
(29, 'No, está perfecto. Incluye hélices de repuesto.',                '2025-03-25 17:55:00', 1, 9,  10, 28),
(30, '¿Funciona en espacios cerrados?',                                 '2025-03-25 18:10:00', 1, 10, 9,  28),
(31, 'Sí, siempre lo usé en interior.',                                 '2025-03-25 18:30:00', 1, 9,  10, 28),
(32, 'Perfecto, lo quiero.',                                            '2025-03-25 18:45:00', 1, 10, 9,  28),
(33, '¿El juego incluye todas las plantillas?',                        '2025-04-23 09:15:00', 1, 12, 9,  30),
(34, 'Sí, completo. Sin piezas faltantes.',                            '2025-04-23 09:50:00', 1, 9,  12, 30),
(35, 'Me lo llevo, ¿envío a Getxo?',                                   '2025-04-23 10:05:00', 1, 12, 9,  30),
(36, 'Sí, envío a toda España por Correos.',                           '2025-04-23 10:20:00', 1, 9,  12, 30);
