INSERT INTO reviews (id_reviews, rating, comment, review_date, fk_items_id, fk_reviewer_id, fk_reviewed_id) VALUES
(1,  5, 'Auriculares en perfecto estado, tal como se describían. Envío rápido.',         '2024-10-17 10:00:00', 3,  16, 4),
(2,  4, 'El proyector llegó bien embalado. Funciona genial. Muy buena atención.',        '2024-10-28 11:00:00', 6,  14, 5),
(3,  5, 'La cámara perfecta. Igual que en las fotos. Muy recomendable.',                 '2024-10-22 12:00:00', 10, 9,  6),
(4,  4, 'Los walkie talkies funcionan bien. Uso normal pero lo que se describía.',       '2024-11-03 13:00:00', 12, 10, 7),
(5,  5, 'La consola llegó perfecta. Mis hijos encantados. Vendedora muy atenta.',        '2024-11-12 14:00:00', 14, 11, 8),
(6,  4, 'El altavoz bien, llegó con un día de retraso pero correcto.',                   '2024-11-15 15:00:00', 17, 12, 8),
(7,  5, 'El LEGO Camión completo y en buen estado. Muy buena vendedora.',                '2024-11-22 16:00:00', 20, 8,  10),
(8,  5, 'La figura de Peely preciosa. Mejor de lo esperado. 100% recomendable.',         '2024-11-26 10:00:00', 23, 16, 13),
(9,  4, 'El LEGO Hogwarts bien. Faltaba una bolsita pequeña pero lo demás completo.',    '2024-11-30 11:00:00', 25, 13, 15),
(10, 5, 'La figura Spider-Man en perfecto estado. Vendedor muy atento y rápido.',        '2024-12-05 12:00:00', 27, 15, 17),
(11, 3, 'El LEGO Technic llegó bien pero la caja estaba muy deteriorada.',               '2024-12-15 13:00:00', 30, 11, 2),
(12, 5, 'La Monster High completa y en buen estado. Muy buena vendedora.',               '2024-12-18 14:00:00', 32, 9,  4),
(13, 5, 'El T-Rex llegó muy bien embalado. Articulaciones perfectas.',                   '2024-12-30 15:00:00', 36, 13, 8),
(14, 4, 'La figura cantante bien. Trato correcto y envío a tiempo.',                     '2025-01-05 16:00:00', 38, 14, 10),
(15, 5, 'Los Pokémon en estado perfecto. Vendedor muy serio.',                           '2025-01-12 17:00:00', 41, 15, 13),
(16, 5, 'El Baby Yoda precioso. Laia es una vendedora excelente.',                       '2025-01-16 18:00:00', 44, 8,  16),
(17, 4, 'El puzzle de España completo. Alguna pieza un poco forzada pero bien.',         '2025-01-22 09:00:00', 46, 12, 3),
(18, 5, 'El Puzzle Stitch perfecto. Usado muy pocas veces. Muy recomendable.',           '2025-01-27 10:00:00', 48, 16, 5),
(19, 5, 'El Puzzle Avengers completo y en buen estado. Excelente vendedor.',             '2025-02-02 11:00:00', 50, 9,  7),
(20, 4, 'Dixit completo, cartas en buen estado. Muy buena vendedora.',                   '2025-02-08 12:00:00', 52, 10, 3),
(21, 5, 'Sushi Go! perfecto. Todo tal como se describía. 5 estrellas.',                  '2025-02-13 13:00:00', 55, 11, 6),
(22, 5, 'El Catan impecable. Elena es una vendedora increíble.',                         '2025-02-18 14:00:00', 60, 12, 11),
(23, 3, 'La tablet llegó con un pequeño arañazo no mencionado. Funciona bien.',          '2025-02-22 15:00:00', 62, 13, 3),
(24, 5, 'El cuentacuentos perfecto. Mejor de lo esperado. Muy recomendable.',            '2025-02-28 16:00:00', 65, 14, 6),
(25, 4, 'La moto correpasillos bien. Uso normal, como se describía.',                    '2025-03-08 17:00:00', 69, 15, 10),
(26, 5, 'La pista Hot Wheels genial. Mis hijos la adoran. Vendedor excelente.',          '2025-03-14 18:00:00', 72, 8,  3),
(27, 5, 'El coche todoterreno en perfecto estado. Muy buena vendedora.',                 '2025-03-20 09:00:00', 75, 9,  6),
(28, 5, 'El drone perfecto, con hélices de repuesto. Muy buen vendedor.',                '2025-04-05 10:00:00', 78, 10, 9),
(29, 4, 'La pizarra magnética bien. Trato correcto y envío rápido.',                     '2025-04-18 11:00:00', 82, 11, 3),
(30, 5, 'El juego de dibujo completo. Muy recomendable. Excelente vendedor.',            '2025-05-06 12:00:00', 88, 12, 9);
